func TestMessagesGetByRFC822LocalHit(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)
	db, err := store.Open(filepath.Join(home, ".local", "share", "superhuman-pp-cli", "data.db"))
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	if _, err := db.UpsertGmailMessages(t.Context(), []store.StoredMessage{{
		ID: "m1", ThreadID: "t1", AccountEmail: "user@example.com", RFC822ID: "<m1@example.com>", Subject: "Hi", InternalDate: time.Now().UnixMilli(),
	}}); err != nil {
		t.Fatalf("upsert: %v", err)
	}
	db.Close()
	configPath, tokenStorePath := withConfigPath(t)
	seedSendStore(t, tokenStorePath, "user@example.com", "gid-001")
	writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")
	stdout, _, err := executeCmd(t, "--config", configPath, "--json", "messages", "get-by-rfc822", "<m1@example.com>")
	if err != nil {
		t.Fatalf("messages get-by-rfc822: %v", err)
	}
	if !strings.Contains(stdout, `"source": "local"`) || !strings.Contains(stdout, `"m1"`) {
		t.Fatalf("local output wrong: %s", stdout)
	}
}

func TestMessagesGetByRFC822Fallback(t *testing.T) {
	var observedQuery string
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		switch {
		case strings.HasSuffix(r.URL.Path, "/users/me/messages") && r.URL.Query().Get("format") == "":
			observedQuery = r.URL.Query().Get("q")
			_, _ = w.Write([]byte(`{"messages":[{"id":"m2","threadId":"t2"}]}`))
		case strings.HasSuffix(r.URL.Path, "/users/me/messages/m2"):
			_, _ = w.Write([]byte(`{"id":"m2","threadId":"t2","payload":{"headers":[]}}`))
		default:
			http.Error(w, "unexpected "+r.URL.String(), 404)
		}
	}))
	defer srv.Close()
	orig := gmail.BaseURL
	gmail.BaseURL = srv.URL
	t.Cleanup(func() { gmail.BaseURL = orig })
	home := t.TempDir()
	t.Setenv("HOME", home)
	configPath, tokenStorePath := withConfigPath(t)
	seedSendStore(t, tokenStorePath, "user@example.com", "gid-001")
	writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")
	stdout, _, err := executeCmd(t, "--config", configPath, "--json", "messages", "get-by-rfc822", "<m2@example.com>")
	if err != nil {
		t.Fatalf("messages get-by-rfc822 fallback: %v", err)
	}
	if observedQuery != "rfc822msgid:m2@example.com" || !strings.Contains(stdout, `"source": "gmail"`) {
		t.Fatalf("fallback query/output wrong query=%q stdout=%s", observedQuery, stdout)
	}
}

